#include <vector>
#include <stdexcept>

template<typename T>
class Stack {
    std::vector<T> items;
public:
    void push(T item) { items.push_back(std::move(item)); }

    T pop() {
        if (items.empty()) throw std::underflow_error("pop from empty stack");
        T top = std::move(items.back());
        items.pop_back();
        return top;
    }
};
